import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../AuthContext';

const Sidebar = ({ role }) => {
  const { user } = useAuth();
  const location = useLocation();

  const employeeMenu = [
    { path: '/employee-dashboard', label: 'Dashboard' },
    { path: '/profile', label: 'My Profile' },
    { path: '/attendance', label: 'Attendance' },
    { path: '/apply-leave', label: 'Apply Leave' },
    { path: '/payroll', label: 'Payroll' },
  ];

  const adminMenu = [
    { path: '/admin-dashboard', label: 'Dashboard' },
    { path: '/profile', label: 'Employee Management' },
    { path: '/attendance', label: 'Attendance Records' },
    { path: '/leave-approvals', label: 'Leave Approvals' },
    { path: '/payroll', label: 'Payroll Management' },
  ];

  const menu = role === 'Admin' ? adminMenu : employeeMenu;

  return (
    <div className="w-64 bg-gray-100 dark:bg-gray-800 h-screen p-4">
      <ul className="space-y-2">
        {menu.map((item) => (
          <li key={item.path}>
            <Link
              to={item.path}
              className={`block px-4 py-2 rounded ${
                location.pathname === item.path
                  ? 'bg-blue-500 text-white'
                  : 'text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700'
              }`}
            >
              {item.label}
            </Link>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default Sidebar;
